-- ----------------------------
-- Table structure for ai_insights
-- ----------------------------
DROP TABLE IF EXISTS `ai_insights`;
CREATE TABLE `ai_insights`  (
  `insight_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID uvida',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `model_used` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'AI model kori????en za analizu',
  `source_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tip analiziranih podataka (npr. faktura, izve??taj)',
  `source_id` bigint NULL DEFAULT NULL COMMENT 'ID zapisa izvornih podataka',
  `prompt` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Prompt kori????en za analizu',
  `insight_summary` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Sa??etak AI uvida',
  `insight_data` json NULL COMMENT 'Detaljni strukturirani podaci uvida',
  `generated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme generisanja uvida',
  PRIMARY KEY (`insight_id`) USING BTREE,
  INDEX `company_id`(`company_id` ASC) USING BTREE,
  CONSTRAINT `ai_insights_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores insights and analyses generated by AI models | SR: ??uva uvide i analize generisane od strane AI modela' ROW_FORMAT = DYNAMIC;

