-- Table structure for ai_training_data
-- ----------------------------
DROP TABLE IF EXISTS `ai_training_data`;
CREATE TABLE `ai_training_data`  (
  `ai_training_data_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID zapisa o AI obu??avanju',
  `company_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu kompanija',
  `content` json NOT NULL COMMENT 'Sadr??aj podataka za obu??avanje',
  `data_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip podataka za obu??avanje',
  `source_file` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv izvornog fajla',
  `model_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tip ciljnog modela',
  `language` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'sr' COMMENT 'Jezik podataka',
  `is_processed` tinyint(1) NULL DEFAULT 0 COMMENT 'Da li su podaci obra??eni',
  `processing_metadata` json NULL COMMENT 'Metapodaci o obradi',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`ai_training_data_id`) USING BTREE,
  INDEX `idx_ai_company_id`(`company_id` ASC) USING BTREE COMMENT 'Indeks za pretragu po kompaniji',
  INDEX `idx_ai_data_type`(`data_type` ASC) USING BTREE COMMENT 'Indeks za tip podataka',
  INDEX `idx_ai_source_file`(`source_file` ASC) USING BTREE COMMENT 'Indeks za izvorni fajl',
  INDEX `idx_ai_model_type`(`model_type` ASC) USING BTREE COMMENT 'Indeks za tip modela',
  INDEX `idx_ai_processed`(`is_processed` ASC) USING BTREE COMMENT 'Indeks za status obrade',
  INDEX `idx_ai_language`(`language` ASC) USING BTREE COMMENT 'Indeks za jezik',
  CONSTRAINT `ai_training_data_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores AI training data from various sources | SR: ??uva podatke za AI obu??avanje iz razli??itih izvora' ROW_FORMAT = DYNAMIC;

