-- ----------------------------
-- Table structure for aml_monitoring
-- ----------------------------
DROP TABLE IF EXISTS `aml_monitoring`;
CREATE TABLE `aml_monitoring`  (
  `aml_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `transaction_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu glavne knjige',
  `customer_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na podatke klijenta',
  `transaction_date` date NOT NULL COMMENT 'Datum transakcije',
  `amount` decimal(15, 2) NOT NULL COMMENT 'Iznos transakcije',
  `currency` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Valuta',
  `is_suspicious` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Da li je transakcija sumnjiva',
  `aml_risk_level` enum('low','medium','high') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'low' COMMENT 'Nivo AML rizika',
  `status_id` bigint NOT NULL COMMENT 'Referenca na tabelu statusa',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`aml_id`) USING BTREE,
  INDEX `idx_aml_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_aml_transaction_id`(`transaction_id` ASC) USING BTREE,
  INDEX `idx_aml_customer_id`(`customer_id` ASC) USING BTREE,
  INDEX `idx_aml_status_id`(`status_id` ASC) USING BTREE,
  CONSTRAINT `aml_monitoring_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `aml_monitoring_ibfk_2` FOREIGN KEY (`transaction_id`) REFERENCES `general_ledger` (`ledger_id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `aml_monitoring_ibfk_3` FOREIGN KEY (`status_id`) REFERENCES `status_types` (`status_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores AML monitoring data | SR: ??uva podatke o AML nadzoru' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of aml_monitoring
-- ----------------------------

-- ----------------------------
-- Table structure for anomalies
-- ----------------------------
DROP TABLE IF EXISTS `anomalies`;
CREATE TABLE `anomalies`  (
  `anomaly_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID anomalije',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `anomaly_type` enum('financial','compliance','operational','security','data_quality') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip anomalije',
  `severity` enum('low','medium','high','critical') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ozbiljnost anomalije',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naslov anomalije',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Opis anomalije',
  `detected_at` timestamp NOT NULL COMMENT 'Kada je anomalija detektovana',
  `resolved_at` timestamp NULL DEFAULT NULL COMMENT 'Kada je anomalija re??ena',
  `status` enum('open','investigating','resolved','false_positive') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'open' COMMENT 'Status anomalije',
  `confidence_score` decimal(5, 2) NULL DEFAULT NULL COMMENT 'AI skor pouzdanosti',
  `affected_records` json NULL COMMENT 'ID-jevi pogo??enih zapisa',
  `resolution_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Napomene o re??avanju',
  `metadata` json NULL COMMENT 'Dodatni metapodaci anomalije',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`anomaly_id`) USING BTREE,
  INDEX `idx_anomaly_company_id`(`company_id` ASC) USING BTREE COMMENT 'Indeks za pretragu po kompaniji',
  INDEX `idx_anomaly_type`(`anomaly_type` ASC) USING BTREE COMMENT 'Indeks za tip anomalije',
  INDEX `idx_anomaly_severity`(`severity` ASC) USING BTREE COMMENT 'Indeks za ozbiljnost',
  INDEX `idx_anomaly_status`(`status` ASC) USING BTREE COMMENT 'Indeks za status',
  INDEX `idx_anomaly_detected_at`(`detected_at` ASC) USING BTREE COMMENT 'Indeks za datum detekcije',
  INDEX `idx_anomaly_resolved_at`(`resolved_at` ASC) USING BTREE COMMENT 'Indeks za datum re??avanja',
  CONSTRAINT `anomalies_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores detected anomalies and issues | SR: ??uva detektovane anomalije i probleme' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of anomalies
