-- ----------------------------
-- Table structure for api_integrations
-- ----------------------------
DROP TABLE IF EXISTS `api_integrations`;
CREATE TABLE `api_integrations`  (
  `api_integration_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID API integracije',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv integracije',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naslov integracije',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Opis integracije',
  `icon` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Ikona integracije',
  `api_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'URL API endpoint-a',
  `api_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'API klju?? (enkriptovan)',
  `is_enabled` tinyint(1) NULL DEFAULT 0 COMMENT 'Da li je integracija omogu??ena',
  `status` enum('active','inactive','error','pending') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'inactive' COMMENT 'Status integracije',
  `last_sync` timestamp NULL DEFAULT NULL COMMENT 'Vreme poslednje sinhronizacije',
  `sync_frequency` int NULL DEFAULT 3600 COMMENT 'Frekvencija sinhronizacije u sekundama',
  `config` json NULL COMMENT 'Konfiguracija integracije',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Poslednja poruka o gre??ci',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`api_integration_id`) USING BTREE,
  UNIQUE INDEX `name`(`name` ASC) USING BTREE,
  INDEX `idx_integrations_name`(`name` ASC) USING BTREE COMMENT 'Indeks za naziv integracije',
  INDEX `idx_integrations_enabled`(`is_enabled` ASC) USING BTREE COMMENT 'Indeks za status omogu??enosti',
  INDEX `idx_integrations_status`(`status` ASC) USING BTREE COMMENT 'Indeks za status integracije',
  INDEX `idx_integrations_last_sync`(`last_sync` ASC) USING BTREE COMMENT 'Indeks za vreme poslednje sinhronizacije'
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores API integrations configuration | SR: ??uva konfiguraciju API integracija' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of api_integrations
-- ----------------------------

-- ----------------------------
-- Table structure for audit_log
-- ----------------------------
DROP TABLE IF EXISTS `audit_log`;
CREATE TABLE `audit_log`  (
  `log_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NULL DEFAULT NULL,
  `action` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `table_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `record_id` bigint NULL DEFAULT NULL,
  `old_values` json NULL,
  `new_values` json NULL,
  `ip_address` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `user_agent` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`log_id`) USING BTREE,
  INDEX `idx_audit_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_audit_table_name`(`table_name` ASC) USING BTREE,
  INDEX `idx_audit_created_at`(`created_at` ASC) USING BTREE,
  CONSTRAINT `audit_log_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores audit trail | SR: ─îuva audit trag' ROW_FORMAT = DYNAMIC;

