-- ----------------------------
-- Table structure for blog_posts
-- ----------------------------
DROP TABLE IF EXISTS `blog_posts`;
CREATE TABLE `blog_posts`  (
  `blog_post_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID blog posta',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naslov blog posta',
  `slug` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'URL slug',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Sadr??aj blog posta',
  `summary` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Sa??etak blog posta',
  `author` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ime autora',
  `tags` json NULL COMMENT 'Tagovi blog posta',
  `is_published` tinyint(1) NULL DEFAULT 1 COMMENT 'Da li je post objavljen',
  `published_date` date NULL DEFAULT NULL COMMENT 'Datum objavljivanja',
  `view_count` int NULL DEFAULT 0 COMMENT 'Broj pregleda',
  `metadata` json NULL COMMENT 'Dodatni metapodaci bloga',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`blog_post_id`) USING BTREE,
  UNIQUE INDEX `slug`(`slug` ASC) USING BTREE,
  INDEX `idx_blog_slug`(`slug` ASC) USING BTREE COMMENT 'Indeks za URL slug',
  INDEX `idx_blog_author`(`author` ASC) USING BTREE COMMENT 'Indeks za autora',
  INDEX `idx_blog_published`(`is_published` ASC) USING BTREE COMMENT 'Indeks za status objavljenosti',
  INDEX `idx_blog_published_date`(`published_date` ASC) USING BTREE COMMENT 'Indeks za datum objavljivanja',
  FULLTEXT INDEX `idx_blog_search`(`title`, `content`, `summary`) COMMENT 'Indeks za pretragu teksta'
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores blog posts and articles | SR: ??uva blog postove i ??lanke' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of blog_posts
-- ----------------------------

