  `challenge_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `question` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `expected_answer` int NOT NULL,
  `user_answer` int NULL DEFAULT NULL,
  `is_correct` tinyint(1) NULL DEFAULT NULL,
  `attempts_count` int NULL DEFAULT 0,
  `ip_address` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `user_agent` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`attempt_id`) USING BTREE,
  INDEX `idx_bot_verification_user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `bot_verification_attempts_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores bot verification attempts | SR: ─îuva poku┼íaje verifikacije bota' ROW_FORMAT = DYNAMIC;

