-- ----------------------------
-- Table structure for capital_adequacy
-- ----------------------------
DROP TABLE IF EXISTS `capital_adequacy`;
CREATE TABLE `capital_adequacy`  (
  `capital_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `report_date` date NOT NULL COMMENT 'Datum izve??taja o kapitalnoj adekvatnosti',
  `tier1_capital` decimal(15, 2) NOT NULL COMMENT 'Kapital prvog nivoa',
  `tier2_capital` decimal(15, 2) NOT NULL COMMENT 'Kapital drugog nivoa',
  `risk_weighted_assets` decimal(15, 2) NOT NULL COMMENT 'Aktiva ponderisana rizikom',
  `capital_adequacy_ratio` decimal(5, 2) NOT NULL COMMENT 'Stopa kapitalne adekvatnosti (%)',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`capital_id`) USING BTREE,
  INDEX `idx_capital_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_capital_report_date`(`report_date` ASC) USING BTREE,
  CONSTRAINT `capital_adequacy_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores capital adequacy data | SR: ??uva podatke o kapitalnoj adekvatnosti' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of capital_adequacy
-- ----------------------------

-- ----------------------------
-- Table structure for cash_flow
-- ----------------------------
DROP TABLE IF EXISTS `cash_flow`;
CREATE TABLE `cash_flow`  (
  `cash_flow_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `transaction_date` date NOT NULL COMMENT 'Datum transakcije nov??anog toka',
  `cash_flow_type` enum('operating','investing','financing') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip nov??anog toka',
  `amount` decimal(15, 2) NOT NULL COMMENT 'Iznos nov??anog toka',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Opis nov??anog toka',
  `source_document_id` bigint NULL DEFAULT NULL COMMENT 'ID izvornog dokumenta',
  `source_document_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tip izvornog dokumenta',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`cash_flow_id`) USING BTREE,
  INDEX `idx_cash_flow_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_cash_flow_type`(`cash_flow_type` ASC) USING BTREE,
  INDEX `idx_cash_flow_transaction_date`(`transaction_date` ASC) USING BTREE,
  CONSTRAINT `cash_flow_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores cash flow transactions | SR: ??uva transakcije nov??anog toka' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of cash_flow
-- ----------------------------

-- ----------------------------
-- Table structure for chart_of_accounts
-- ----------------------------
DROP TABLE IF EXISTS `chart_of_accounts`;
CREATE TABLE `chart_of_accounts`  (
  `account_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `account_code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '??ifra konta prema srpskom kontnom planu',
  `account_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv konta',
  `account_type` enum('asset','liability','equity','revenue','expense') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip konta',
  `is_active` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Da li je konto aktivan',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`account_id`) USING BTREE,
  UNIQUE INDEX `uk_company_account_code`(`company_id` ASC, `account_code` ASC) USING BTREE,
  INDEX `idx_account_company_id`(`company_id` ASC) USING BTREE,
  CONSTRAINT `chart_of_accounts_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores accounts per Serbian Chart of Accounts | SR: ??uva konta prema srpskom kontnom planu' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of chart_of_accounts
-- ----------------------------

-- ----------------------------
-- Table structure for chat_sessions
-- ----------------------------
DROP TABLE IF EXISTS `chat_sessions`;
CREATE TABLE `chat_sessions`  (
  `session_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `session_token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `query` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `response` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `language` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'en',
  `confidence_score` decimal(5, 4) NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`session_id`) USING BTREE,
  INDEX `idx_chat_session_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_chat_session_token`(`session_token` ASC) USING BTREE,
  CONSTRAINT `chat_sessions_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores chat sessions | SR: ─îuva chat sesije' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of chat_sessions
-- ----------------------------

-- ----------------------------
-- Table structure for chat_transcripts
-- ----------------------------
DROP TABLE IF EXISTS `chat_transcripts`;
CREATE TABLE `chat_transcripts`  (
  `transcript_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `session_ids` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `format` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'json',
  `file_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`transcript_id`) USING BTREE,
  INDEX `idx_chat_transcript_user_id`(`user_id` ASC) USING BTREE,
  CONSTRAINT `chat_transcripts_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores chat transcripts | SR: ─îuva chat transkripte' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of chat_transcripts
-- ----------------------------

-- ----------------------------
-- Table structure for cities
-- ----------------------------
DROP TABLE IF EXISTS `cities`;
CREATE TABLE `cities`  (
  `city_id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `region_id` int UNSIGNED NOT NULL,
  `country_id` smallint UNSIGNED NOT NULL,
  `latitude` decimal(10, 8) NOT NULL,
  `longitude` decimal(11, 8) NOT NULL,
  `population` bigint UNSIGNED NULL DEFAULT NULL,
  `timezone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`city_id`) USING BTREE,
  INDEX `idx_city_region_id`(`region_id` ASC) USING BTREE,
  INDEX `idx_city_country_id`(`country_id` ASC) USING BTREE,
  INDEX `idx_city_lat_long`(`latitude` ASC, `longitude` ASC) USING BTREE,
  CONSTRAINT `cities_ibfk_1` FOREIGN KEY (`region_id`) REFERENCES `regions` (`region_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `cities_ibfk_2` FOREIGN KEY (`country_id`) REFERENCES `countries` (`country_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: World cities data | SR: Podaci o gradovima sveta' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of cities
-- ----------------------------

-- ----------------------------
-- Table structure for companies
-- ----------------------------
DROP TABLE IF EXISTS `companies`;
CREATE TABLE `companies`  (
  `company_id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv kompanije',
  `tax_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Poreski ID',
  `registration_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Mati??ni broj',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Adresa',
  `city` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Grad',
  `country` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Dr??ava',
  `industry` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Industrija',
  `is_active` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Da li je kompanija aktivna',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`company_id`) USING BTREE,
  UNIQUE INDEX `uk_tax_id`(`tax_id` ASC) USING BTREE,
  UNIQUE INDEX `uk_registration_number`(`registration_number` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores company data | SR: ??uva podatke o kompanijama' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of companies
-- ----------------------------

-- ----------------------------
-- Table structure for consent_records
-- ----------------------------
DROP TABLE IF EXISTS `consent_records`;
CREATE TABLE `consent_records`  (
  `consent_record_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID zapisa o saglasnosti',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `data_subject_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Identifikator nosioca podataka',
  `consent_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip saglasnosti',
  `consent_given` tinyint(1) NOT NULL COMMENT 'Da li je saglasnost data',
  `consent_date` timestamp NOT NULL COMMENT 'Kada je saglasnost data/povu??ena',
  `withdrawal_date` timestamp NULL DEFAULT NULL COMMENT 'Kada je saglasnost povu??ena',
  `processing_purposes` json NULL COMMENT 'Svrhe za koje je saglasnost data',
  `consent_method` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Metod prikupljanja saglasnosti',
  `ip_address` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'IP adresa kada je saglasnost data',
  `user_agent` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'User agent kada je saglasnost data',
  `metadata` json NULL COMMENT 'Dodatni metapodaci saglasnosti',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`consent_record_id`) USING BTREE,
  INDEX `idx_consent_company_id`(`company_id` ASC) USING BTREE COMMENT 'Indeks za pretragu po kompaniji',
  INDEX `idx_consent_subject_id`(`data_subject_id` ASC) USING BTREE COMMENT 'Indeks za nosioca podataka',
