-- ----------------------------
-- Table structure for documents
-- ----------------------------
DROP TABLE IF EXISTS `documents`;
CREATE TABLE `documents`  (
  `document_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID dokumenta',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `document_type_id` bigint NOT NULL COMMENT 'Referenca na tabelu tipova dokumenata',
  `document_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv ili naslov dokumenta',
  `file_path` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Putanja do sa??uvanog dokumenta',
  `issue_date` date NULL DEFAULT NULL COMMENT 'Datum izdavanja dokumenta',
  `expiry_date` date NULL DEFAULT NULL COMMENT 'Datum isteka dokumenta',
  `source_system` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Izvorni sistem kao ??to je eUprava',
  `metadata` json NULL COMMENT 'Dodatni metapodaci',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`document_id`) USING BTREE,
  INDEX `company_id`(`company_id` ASC) USING BTREE,
  INDEX `document_type_id`(`document_type_id` ASC) USING BTREE,
  CONSTRAINT `documents_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `documents_ibfk_2` FOREIGN KEY (`document_type_id`) REFERENCES `document_types` (`document_type_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores various company-related documents | SR: ??uva razli??ite dokumente vezane za kompaniju' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of documents
