-- ----------------------------
-- Table structure for employee_data
-- ----------------------------
DROP TABLE IF EXISTS `employee_data`;
CREATE TABLE `employee_data`  (
  `employee_data_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID zapisa o zaposlenom',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `employee_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ID zaposlenog',
  `employee_number` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Broj zaposlenog',
  `first_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ime zaposlenog',
  `last_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Prezime zaposlenog',
  `department` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Odeljenje',
  `position` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Pozicija',
  `salary` decimal(15, 2) NULL DEFAULT NULL COMMENT 'Osnovna plata',
  `hire_date` date NULL DEFAULT NULL COMMENT 'Datum zaposlenja',
  `is_active` tinyint(1) NULL DEFAULT 1 COMMENT 'Status aktivnosti zaposlenog',
  `net_salary` decimal(15, 2) NULL DEFAULT NULL COMMENT 'Neto zarada',
  `employee_contributions` decimal(15, 2) NULL DEFAULT NULL COMMENT 'Na teret zaposlenog',
  `employer_contributions` decimal(15, 2) NULL DEFAULT NULL COMMENT 'Na teret poslodavca',
  `gross_salary_2` decimal(15, 2) NULL DEFAULT NULL COMMENT 'Bruto 2',
  `metadata` json NULL COMMENT 'Dodatni metapodaci o zaposlenom',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`employee_data_id`) USING BTREE,
  UNIQUE INDEX `employee_id`(`employee_id` ASC) USING BTREE,
  INDEX `idx_employee_company_id`(`company_id` ASC) USING BTREE COMMENT 'Indeks za pretragu po kompaniji',
  INDEX `idx_employee_id`(`employee_id` ASC) USING BTREE COMMENT 'Indeks za ID zaposlenog',
  INDEX `idx_employee_department`(`department` ASC) USING BTREE COMMENT 'Indeks za odeljenje',
  INDEX `idx_employee_active`(`is_active` ASC) USING BTREE COMMENT 'Indeks za aktivne zaposlene',
  INDEX `idx_employee_hire_date`(`hire_date` ASC) USING BTREE COMMENT 'Indeks za datum zaposlenja',
  FULLTEXT INDEX `idx_employee_search`(`first_name`, `last_name`, `department`, `position`) COMMENT 'Indeks za pretragu teksta',
  CONSTRAINT `employee_data_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores comprehensive employee data | SR: ??uva sveobuhvatne podatke o zaposlenima' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of employee_data
