-- ----------------------------
-- Table structure for employee_training
-- ----------------------------
DROP TABLE IF EXISTS `employee_training`;
CREATE TABLE `employee_training`  (
  `training_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `employee_data_id` bigint NOT NULL COMMENT 'Referenca na tabelu zaposlenih',
  `training_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv obuke',
  `training_date` date NOT NULL COMMENT 'Datum obuke',
  `certification_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Broj sertifikata',
  `expiry_date` date NULL DEFAULT NULL COMMENT 'Datum isteka sertifikata',
  `status_id` bigint NOT NULL COMMENT 'Referenca na tabelu statusa',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`training_id`) USING BTREE,
  INDEX `idx_training_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_training_employee_id`(`employee_data_id` ASC) USING BTREE,
  INDEX `idx_training_status_id`(`status_id` ASC) USING BTREE,
  CONSTRAINT `employee_training_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `employee_training_ibfk_2` FOREIGN KEY (`employee_data_id`) REFERENCES `employee_data` (`employee_data_id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `employee_training_ibfk_3` FOREIGN KEY (`status_id`) REFERENCES `status_types` (`status_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores employee training data | SR: ??uva podatke o obukama zaposlenih' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of employee_training
-- ----------------------------

-- ----------------------------
-- Table structure for employees
-- ----------------------------
DROP TABLE IF EXISTS `employees`;
CREATE TABLE `employees`  (
  `employee_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NULL DEFAULT NULL,
  `company_id` bigint NOT NULL,
  `first_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `last_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `position` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `department_id` bigint NULL DEFAULT NULL,
  `hire_date` date NOT NULL,
  `salary` decimal(10, 2) NULL DEFAULT NULL,
  `status` enum('active','inactive','terminated') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`employee_id`) USING BTREE,
  INDEX `idx_employee_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_employee_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_employee_department_id`(`department_id` ASC) USING BTREE,
  CONSTRAINT `employees_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `employees_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores employee information | SR: ─îuva informacije o zaposlenima' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of employees
