-- ----------------------------
-- Table structure for error_messages
-- ----------------------------
DROP TABLE IF EXISTS `error_messages`;
CREATE TABLE `error_messages`  (
  `error_message_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID poruke o gre??ci',
  `error_code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'HTTP kod gre??ke',
  `language` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Kod jezika',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naslov gre??ke',
  `message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Poruka o gre??ci',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Opis gre??ke',
  `is_default` tinyint(1) NULL DEFAULT 0 COMMENT 'Da li je ovo podrazumevana poruka',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`error_message_id`) USING BTREE,
  UNIQUE INDEX `uk_error_lang`(`error_code` ASC, `language` ASC) USING BTREE COMMENT 'Jedinstveno ograni??enje za kod gre??ke i jezik',
  INDEX `idx_errors_code`(`error_code` ASC) USING BTREE COMMENT 'Indeks za kod gre??ke',
  INDEX `idx_errors_language`(`language` ASC) USING BTREE COMMENT 'Indeks za jezik',
  INDEX `idx_errors_default`(`is_default` ASC) USING BTREE COMMENT 'Indeks za status podrazumevanosti'
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores localized error messages | SR: ??uva lokalizovane poruke o gre??kama' ROW_FORMAT = DYNAMIC;

