-- ----------------------------
-- Table structure for financial_data
-- ----------------------------
DROP TABLE IF EXISTS `financial_data`;
CREATE TABLE `financial_data`  (
  `financial_data_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID finansijskog zapisa',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `transaction_date` date NOT NULL COMMENT 'Datum transakcije',
  `transaction_type` enum('income','expense','transfer','investment') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip transakcije',
  `amount` decimal(15, 2) NOT NULL COMMENT 'Iznos transakcije',
  `currency` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'RSD' COMMENT 'Kod valute',
  `category_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu kategorija transakcija',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Opis transakcije',
  `reference_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Referentni broj',
  `source_document_id` bigint NULL DEFAULT NULL COMMENT 'Veza ka izvornom dokumentu (npr. ID fakture)',
  `source_document_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tip izvornog dokumenta (npr. faktura)',
  `source_system` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Izvorni sistem',
  `location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Lokacija transakcije',
  `is_reconciled` tinyint(1) NULL DEFAULT 0 COMMENT 'Status uskla??ivanja',
  `metadata` json NULL COMMENT 'Dodatni metapodaci transakcije',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`financial_data_id`) USING BTREE,
  INDEX `idx_financial_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_financial_date`(`transaction_date` ASC) USING BTREE,
  INDEX `idx_financial_type`(`transaction_type` ASC) USING BTREE,
  INDEX `idx_financial_category`(`category_id` ASC) USING BTREE,
  INDEX `idx_financial_location`(`location` ASC) USING BTREE,
  INDEX `idx_financial_reconciled`(`is_reconciled` ASC) USING BTREE,
  CONSTRAINT `financial_data_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `financial_data_ibfk_2` FOREIGN KEY (`category_id`) REFERENCES `transaction_categories` (`category_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 379 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores financial transaction data | SR: ??uva podatke o finansijskim transakcijama' ROW_FORMAT = DYNAMIC;

