-- ----------------------------
-- Table structure for financial_forecasts
-- ----------------------------
DROP TABLE IF EXISTS `financial_forecasts`;
CREATE TABLE `financial_forecasts`  (
  `forecast_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL,
  `forecast_type` enum('revenue','expense','cash_flow','profit') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `period` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `amount` decimal(15, 2) NOT NULL,
  `confidence_level` decimal(5, 2) NULL DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`forecast_id`) USING BTREE,
  INDEX `idx_forecast_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_forecast_type`(`forecast_type` ASC) USING BTREE,
  CONSTRAINT `financial_forecasts_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores financial forecasts | SR: ─îuva finansijske prognoze' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of financial_forecasts
-- ----------------------------

-- ----------------------------
-- Table structure for financial_statements
-- ----------------------------
DROP TABLE IF EXISTS `financial_statements`;
CREATE TABLE `financial_statements`  (
  `statement_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID izve??taja',
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `statement_type` enum('balance_sheet','income_statement','cash_flow') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip finansijskog izve??taja',
  `year` int NOT NULL COMMENT 'Fiskalna godina izve??taja',
  `period` enum('annual','quarterly','monthly') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Period izve??taja',
  `source_system` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'APR' COMMENT 'Izvorni sistem kao ??to je APR',
  `metadata` json NULL COMMENT 'Dodatni metapodaci',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`statement_id`) USING BTREE,
  UNIQUE INDEX `uk_statement_company_type_year_period`(`company_id` ASC, `statement_type` ASC, `year` ASC, `period` ASC) USING BTREE,
  CONSTRAINT `financial_statements_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores official financial statements | SR: ??uva zvani??ne finansijske izve??taje' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of financial_statements
-- ----------------------------

-- ----------------------------
-- Table structure for fixed_assets
-- ----------------------------
DROP TABLE IF EXISTS `fixed_assets`;
CREATE TABLE `fixed_assets`  (
  `asset_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `asset_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv osnovnog sredstva',
  `asset_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip osnovnog sredstva',
  `acquisition_date` date NOT NULL COMMENT 'Datum nabavke',
  `acquisition_cost` decimal(15, 2) NOT NULL COMMENT 'Nabavna vrednost',
  `depreciation_rate` decimal(5, 2) NOT NULL COMMENT 'Godi??nja stopa amortizacije (%)',
  `accumulated_depreciation` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT 'Akumulirana amortizacija',
  `net_book_value` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT 'Neto knjigovodstvena vrednost',
  `is_active` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Da li je sredstvo aktivno',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`asset_id`) USING BTREE,
  INDEX `idx_asset_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_asset_type`(`asset_type` ASC) USING BTREE,
  CONSTRAINT `fixed_assets_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores fixed assets and depreciation data | SR: ??uva osnovna sredstva i podatke o amortizaciji' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of fixed_assets
-- ----------------------------

-- ----------------------------
-- Table structure for foreign_exchange_transactions
-- ----------------------------
DROP TABLE IF EXISTS `foreign_exchange_transactions`;
CREATE TABLE `foreign_exchange_transactions`  (
  `fx_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `transaction_date` date NOT NULL COMMENT 'Datum transakcije',
  `amount_from` decimal(15, 2) NOT NULL COMMENT 'Iznos u izvornoj valuti',
  `currency_from` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Izvorna valuta',
  `amount_to` decimal(15, 2) NOT NULL COMMENT 'Iznos u ciljnoj valuti',
  `currency_to` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ciljna valuta',
  `exchange_rate` decimal(10, 6) NOT NULL COMMENT 'Kurs',
  `ledger_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu glavne knjige',
  `status_id` bigint NOT NULL COMMENT 'Referenca na tabelu statusa',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`fx_id`) USING BTREE,
  INDEX `idx_fx_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_fx_ledger_id`(`ledger_id` ASC) USING BTREE,
  INDEX `idx_fx_status_id`(`status_id` ASC) USING BTREE,
  CONSTRAINT `fx_transactions_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fx_transactions_ibfk_2` FOREIGN KEY (`ledger_id`) REFERENCES `general_ledger` (`ledger_id`) ON DELETE SET NULL ON UPDATE RESTRICT,
  CONSTRAINT `fx_transactions_ibfk_3` FOREIGN KEY (`status_id`) REFERENCES `status_types` (`status_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores foreign exchange transactions | SR: ??uva devizne transakcije' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of foreign_exchange_transactions
-- ----------------------------

-- ----------------------------
-- Table structure for general_ledger
-- ----------------------------
DROP TABLE IF EXISTS `general_ledger`;
CREATE TABLE `general_ledger`  (
  `ledger_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `account_id` bigint NOT NULL COMMENT 'Referenca na tabelu kontnog plana',
  `transaction_date` date NOT NULL COMMENT 'Datum transakcije',
  `debit` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT 'Iznos dugovanja',
  `credit` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT 'Iznos potra??ivanja',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Opis transakcije',
  `source_document_id` bigint NULL DEFAULT NULL COMMENT 'ID izvornog dokumenta',
  `source_document_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tip izvornog dokumenta',
  `is_reconciled` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Da li je transakcija uskla??ena',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`ledger_id`) USING BTREE,
  INDEX `idx_ledger_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_ledger_account_id`(`account_id` ASC) USING BTREE,
  INDEX `idx_ledger_transaction_date`(`transaction_date` ASC) USING BTREE,
  CONSTRAINT `general_ledger_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `general_ledger_ibfk_2` FOREIGN KEY (`account_id`) REFERENCES `chart_of_accounts` (`account_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores general ledger entries | SR: ??uva stavke glavne knjige' ROW_FORMAT = DYNAMIC;

