DROP TABLE IF EXISTS `inventory`;
CREATE TABLE `inventory`  (
  `inventory_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `item_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv artikla',
  `item_type` enum('raw_material','work_in_progress','finished_good') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip zaliha',
  `quantity` decimal(15, 2) NOT NULL COMMENT 'Koli??ina na zalihama',
  `unit_price` decimal(15, 2) NOT NULL COMMENT 'Jedini??na cena',
  `total_value` decimal(15, 2) NOT NULL COMMENT 'Ukupna vrednost',
  `warehouse_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Lokacija skladi??ta',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`inventory_id`) USING BTREE,
  INDEX `idx_inventory_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_inventory_item_type`(`item_type` ASC) USING BTREE,
  CONSTRAINT `inventory_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores inventory data for manufacturing/retail | SR: ??uva podatke o zalihama' ROW_FORMAT = DYNAMIC;

