-- Table structure for invoices
-- ----------------------------
DROP TABLE IF EXISTS `invoices`;
CREATE TABLE `invoices`  (
  `invoice_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID fakture',
  `company_id` bigint NOT NULL COMMENT 'Kompanija vlasnik zapisa o fakturi',
  `business_partner_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu poslovnih partnera',
  `invoice_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Broj fakture',
  `invoice_type` enum('sales','purchase') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip fakture',
  `status` enum('draft','sent','paid','overdue','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft' COMMENT 'Status fakture',
  `issue_date` date NOT NULL COMMENT 'Datum izdavanja fakture',
  `due_date` date NULL DEFAULT NULL COMMENT 'Datum dospe??a',
  `total_amount` decimal(15, 2) NOT NULL COMMENT 'Ukupan iznos fakture',
  `vat_amount` decimal(15, 2) NOT NULL COMMENT 'Ukupan iznos PDV-a',
  `currency` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'RSD' COMMENT 'Kod valute',
  `source_system` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'eFaktura' COMMENT 'Izvorni sistem kao ??to je eFaktura',
  `source_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Jedinstveni ID iz izvornog sistema',
  `metadata` json NULL COMMENT 'Dodatni metapodaci',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`invoice_id`) USING BTREE,
  UNIQUE INDEX `uk_invoice_company_number`(`company_id` ASC, `invoice_number` ASC, `invoice_type` ASC) USING BTREE COMMENT 'Jedinstven broj fakture po kompaniji i tipu',
  UNIQUE INDEX `source_id`(`source_id` ASC) USING BTREE,
  INDEX `business_partner_id`(`business_partner_id` ASC) USING BTREE,
  CONSTRAINT `invoices_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `invoices_ibfk_2` FOREIGN KEY (`business_partner_id`) REFERENCES `business_partners` (`business_partner_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 170 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores sales and purchase invoices | SR: ??uva izdate i primljene fakture' ROW_FORMAT = DYNAMIC;

