-- ----------------------------
-- Table structure for location_data
-- ----------------------------
DROP TABLE IF EXISTS `location_data`;
CREATE TABLE `location_data`  (
  `location_data_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID zapisa o lokaciji',
  `city` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv grada',
  `postal_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Po??tanski broj',
  `region` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Naziv regiona',
  `country` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'Serbia' COMMENT 'Naziv dr??ave',
  `latitude` decimal(10, 8) NULL DEFAULT NULL COMMENT 'Geografska ??irina',
  `longitude` decimal(11, 8) NULL DEFAULT NULL COMMENT 'Geografska du??ina',
  `is_active` tinyint(1) NULL DEFAULT 1 COMMENT 'Status aktivnosti lokacije',
  `metadata` json NULL COMMENT 'Dodatni metapodaci lokacije',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`location_data_id`) USING BTREE,
  UNIQUE INDEX `uk_location_city`(`city` ASC, `country` ASC) USING BTREE COMMENT 'Jedinstveno ograni??enje za grad i dr??avu',
  INDEX `idx_location_city`(`city` ASC) USING BTREE COMMENT 'Indeks za grad',
  INDEX `idx_location_region`(`region` ASC) USING BTREE COMMENT 'Indeks za region',
  INDEX `idx_location_country`(`country` ASC) USING BTREE COMMENT 'Indeks za dr??avu',
  INDEX `idx_location_active`(`is_active` ASC) USING BTREE COMMENT 'Indeks za status aktivnosti',
  INDEX `idx_location_coordinates`(`latitude` ASC, `longitude` ASC) USING BTREE COMMENT 'Indeks za koordinate'
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores location and geographical data | SR: ??uva podatke o lokacijama i geografiji' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of location_data
-- ----------------------------

-- ----------------------------
-- Table structure for metadata
-- ----------------------------
DROP TABLE IF EXISTS `metadata`;
CREATE TABLE `metadata`  (
  `metadata_id` bigint NOT NULL AUTO_INCREMENT,
  `entity_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip entiteta (npr. kompanija, faktura)',
  `entity_id` bigint NOT NULL COMMENT 'ID entiteta',
  `metadata_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Klju?? za metapodatke',
  `metadata_value` json NOT NULL COMMENT 'Vrednost metapodataka',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`metadata_id`) USING BTREE,
  INDEX `idx_metadata_entity`(`entity_type` ASC, `entity_id` ASC) USING BTREE,
  INDEX `idx_metadata_key`(`metadata_key` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Centralized metadata storage | SR: Centralizovano skladi??tenje metapodataka' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of metadata
-- ----------------------------

-- ----------------------------
-- Table structure for nbs_financial_data
-- ----------------------------
DROP TABLE IF EXISTS `nbs_financial_data`;
CREATE TABLE `nbs_financial_data`  (
  `nbs_id` bigint NOT NULL AUTO_INCREMENT,
  `company_mbr` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `report_date` date NOT NULL,
  `report_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `total_assets` decimal(20, 2) NULL DEFAULT NULL,
  `current_assets` decimal(20, 2) NULL DEFAULT NULL,
  `non_current_assets` decimal(20, 2) NULL DEFAULT NULL,
  `total_liabilities` decimal(20, 2) NULL DEFAULT NULL,
  `current_liabilities` decimal(20, 2) NULL DEFAULT NULL,
  `non_current_liabilities` decimal(20, 2) NULL DEFAULT NULL,
  `equity` decimal(20, 2) NULL DEFAULT NULL,
  `revenue` decimal(20, 2) NULL DEFAULT NULL,
  `expenses` decimal(20, 2) NULL DEFAULT NULL,
  `net_income` decimal(20, 2) NULL DEFAULT NULL,
  `ebitda` decimal(20, 2) NULL DEFAULT NULL,
  `cash_flow_operating` decimal(20, 2) NULL DEFAULT NULL,
  `cash_flow_investing` decimal(20, 2) NULL DEFAULT NULL,
  `cash_flow_financing` decimal(20, 2) NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`nbs_id`) USING BTREE,
  INDEX `idx_nbs_company_mbr`(`company_mbr` ASC) USING BTREE,
  INDEX `idx_nbs_report_date`(`report_date` ASC) USING BTREE,
  INDEX `idx_nbs_report_type`(`report_type` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: NBS financial data | SR: NBS finansijski podaci' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of nbs_financial_data
-- ----------------------------

-- ----------------------------
-- Table structure for notifications
-- ----------------------------
DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications`  (
  `notification_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` enum('info','warning','error','success') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'info',
  `is_read` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`notification_id`) USING BTREE,
  INDEX `idx_notification_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_notification_is_read`(`is_read` ASC) USING BTREE,
  CONSTRAINT `notifications_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores user notifications | SR: ─îuva korisni─ìke obave┼ítenja' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of notifications
-- ----------------------------

-- ----------------------------
-- Table structure for password_resets
-- ----------------------------
DROP TABLE IF EXISTS `password_resets`;
CREATE TABLE `password_resets`  (
  `reset_id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_used` tinyint(1) NOT NULL DEFAULT 0,
  `expires_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`reset_id`) USING BTREE,
  INDEX `idx_password_reset_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_password_reset_token`(`token` ASC) USING BTREE,
  CONSTRAINT `password_resets_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores password reset tokens | SR: ─îuva tokene za resetovanje lozinke' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of password_resets
