-- ----------------------------
-- Table structure for payment_transactions
-- ----------------------------
DROP TABLE IF EXISTS `payment_transactions`;
CREATE TABLE `payment_transactions`  (
  `transaction_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL,
  `user_id` bigint NULL DEFAULT NULL,
  `amount` decimal(15, 2) NOT NULL,
  `currency` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'RSD',
  `payment_method` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('pending','completed','failed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `reference_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`transaction_id`) USING BTREE,
  INDEX `idx_payment_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_payment_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_payment_status`(`status` ASC) USING BTREE,
  CONSTRAINT `payment_transactions_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `payment_transactions_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores payment transactions | SR: ─îuva transakcije pla─çanja' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of payment_transactions
-- ----------------------------

-- ----------------------------
-- Table structure for payroll
-- ----------------------------
DROP TABLE IF EXISTS `payroll`;
CREATE TABLE `payroll`  (
  `payroll_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `employee_data_id` bigint NOT NULL COMMENT 'Referenca na tabelu zaposlenih',
  `pay_period` varchar(7) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Obra??unski period (GGGG-MM)',
  `gross_salary` decimal(15, 2) NOT NULL COMMENT 'Bruto plata',
  `net_salary` decimal(15, 2) NOT NULL COMMENT 'Neto plata',
  `tax_amount` decimal(15, 2) NOT NULL COMMENT 'Iznos poreza na dohodak',
  `pension_contribution` decimal(15, 2) NOT NULL COMMENT 'Iznos doprinosa za penzijsko osiguranje',
  `health_contribution` decimal(15, 2) NOT NULL COMMENT 'Iznos doprinosa za zdravstveno osiguranje',
  `other_deductions` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT 'Ostali odbitci',
  `payment_date` date NOT NULL COMMENT 'Datum isplate',
  `status_id` bigint NOT NULL COMMENT 'Referenca na tabelu statusa',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`payroll_id`) USING BTREE,
  INDEX `idx_payroll_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_payroll_employee_id`(`employee_data_id` ASC) USING BTREE,
  INDEX `idx_payroll_pay_period`(`pay_period` ASC) USING BTREE,
  INDEX `payroll_ibfk_3`(`status_id` ASC) USING BTREE,
  CONSTRAINT `payroll_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `payroll_ibfk_3` FOREIGN KEY (`status_id`) REFERENCES `status_types` (`status_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores payroll data | SR: ??uva podatke o obra??unu plata' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of payroll
-- ----------------------------

