-- Table structure for postal_codes
-- ----------------------------
DROP TABLE IF EXISTS `postal_codes`;
CREATE TABLE `postal_codes`  (
  `postal_id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `postal_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `city_id` int UNSIGNED NOT NULL,
  `region_id` int UNSIGNED NOT NULL,
  `country_id` smallint UNSIGNED NOT NULL,
  `latitude` decimal(10, 8) NULL DEFAULT NULL,
  `longitude` decimal(11, 8) NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`postal_id`) USING BTREE,
  INDEX `idx_postal_code`(`postal_code` ASC) USING BTREE,
  INDEX `idx_postal_city_id`(`city_id` ASC) USING BTREE,
  INDEX `idx_postal_region_id`(`region_id` ASC) USING BTREE,
  INDEX `idx_postal_country_id`(`country_id` ASC) USING BTREE,
  CONSTRAINT `postal_codes_ibfk_1` FOREIGN KEY (`city_id`) REFERENCES `cities` (`city_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `postal_codes_ibfk_2` FOREIGN KEY (`region_id`) REFERENCES `regions` (`region_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `postal_codes_ibfk_3` FOREIGN KEY (`country_id`) REFERENCES `countries` (`country_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: World postal codes data | SR: Podaci o po┼ítanskim kodovima' ROW_FORMAT = DYNAMIC;

