  `license_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tip licence (npr. Odgovorni projektant, izvo??a??)',
  `issue_date` date NOT NULL COMMENT 'Datum izdavanja licence',
  `expiry_date` date NULL DEFAULT NULL COMMENT 'Datum isteka licence',
  `is_active` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Da li je menad??er aktivan',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`manager_id`) USING BTREE,
  INDEX `idx_manager_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_manager_employee_id`(`employee_data_id` ASC) USING BTREE,
  CONSTRAINT `professional_managers_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `professional_managers_ibfk_2` FOREIGN KEY (`employee_data_id`) REFERENCES `employee_data` (`employee_data_id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores professional manager data for construction | SR: ??uva podatke o profesionalnim menad??erima za gra??evinarstvo' ROW_FORMAT = DYNAMIC;

