-- ----------------------------
-- Table structure for tax_declarations
-- ----------------------------
DROP TABLE IF EXISTS `tax_declarations`;
CREATE TABLE `tax_declarations`  (
  `declaration_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL,
  `declaration_type_id` bigint NOT NULL,
  `period` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `filing_date` date NOT NULL,
  `due_date` date NOT NULL,
  `amount` decimal(15, 2) NOT NULL,
  `status` enum('draft','filed','approved','rejected') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`declaration_id`) USING BTREE,
  INDEX `idx_tax_declaration_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_tax_declaration_type_id`(`declaration_type_id` ASC) USING BTREE,
  INDEX `idx_tax_declaration_status`(`status` ASC) USING BTREE,
  CONSTRAINT `tax_declarations_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `tax_declarations_ibfk_2` FOREIGN KEY (`declaration_type_id`) REFERENCES `tax_declaration_types` (`tax_declaration_type_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores tax declarations | SR: ─îuva poreske prijave' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of tax_declarations
-- ----------------------------

