  `rate_percentage` decimal(5, 2) NOT NULL,
  `effective_date` date NOT NULL,
  `end_date` date NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`rate_id`) USING BTREE,
  INDEX `idx_tax_rate_type`(`tax_type` ASC) USING BTREE,
  INDEX `idx_tax_rate_effective_date`(`effective_date` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores tax rates | SR: ─îuva poreske stope' ROW_FORMAT = DYNAMIC;

