DROP TABLE IF EXISTS `transaction_categories`;
CREATE TABLE `transaction_categories`  (
  `category_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID kategorije',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Naziv kategorije',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Opis kategorije',
  `parent_category_id` bigint NULL DEFAULT NULL COMMENT 'Za hijerarhijske kategorije (npr. Prodaja -> Prodaja proizvoda)',
