  INDEX `parent_category_id`(`parent_category_id` ASC) USING BTREE,
  CONSTRAINT `transaction_categories_ibfk_1` FOREIGN KEY (`parent_category_id`) REFERENCES `transaction_categories` (`category_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores hierarchical categories for financial transactions | SR: ??uva hijerarhijske kategorije za finansijske transakcije' ROW_FORMAT = DYNAMIC;

