-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users`  (
  `user_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Jedinstveni ID korisnika',
  `company_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu kompanija',
  `email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Email adresa korisnika',
  `password_hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Hashirana lozinka',
  `first_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ime korisnika',
  `last_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Prezime korisnika',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Broj telefona korisnika',
  `is_active` tinyint(1) NULL DEFAULT 1 COMMENT 'Status aktivnosti korisnika',
  `account_locked_until` timestamp NULL DEFAULT NULL COMMENT 'Istek blokade naloga',
  `last_login` timestamp NULL DEFAULT NULL COMMENT 'Vreme poslednjeg prijavljivanja',
  `two_factor_enabled` tinyint(1) NULL DEFAULT 0 COMMENT 'Status omogu??enog 2FA',
  `two_factor_secret` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tajni klju?? za 2FA',
  `role_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'user' COMMENT 'Tip korisni??ke uloge',
  `permissions` json NULL COMMENT 'Korisni??ke dozvole',
  `preferences` json NULL COMMENT 'Korisni??ke preferencije',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Vreme kreiranja zapisa',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Vreme a??uriranja zapisa',
  PRIMARY KEY (`user_id`) USING BTREE,
  UNIQUE INDEX `email`(`email` ASC) USING BTREE,
  INDEX `idx_users_company_id`(`company_id` ASC) USING BTREE COMMENT 'Indeks za pretragu po kompaniji',
  INDEX `idx_users_email`(`email` ASC) USING BTREE COMMENT 'Indeks za pretragu po email-u',
  INDEX `idx_users_active`(`is_active` ASC) USING BTREE COMMENT 'Indeks za aktivne korisnike',
  INDEX `idx_users_role`(`role_type` ASC) USING BTREE COMMENT 'Indeks za tip uloge',
  FULLTEXT INDEX `idx_users_search`(`first_name`, `last_name`, `email`) COMMENT 'Indeks za pretragu teksta',
  CONSTRAINT `users_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores user accounts and profiles | SR: ??uva korisni??ke naloge i profile' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of users
-- ----------------------------

-- ----------------------------
-- Table structure for vat_records
-- ----------------------------
DROP TABLE IF EXISTS `vat_records`;
CREATE TABLE `vat_records`  (
  `vat_record_id` bigint NOT NULL AUTO_INCREMENT,
  `company_id` bigint NOT NULL COMMENT 'Referenca na tabelu kompanija',
  `invoice_id` bigint NULL DEFAULT NULL COMMENT 'Referenca na tabelu faktura',
  `transaction_date` date NOT NULL COMMENT 'Datum PDV transakcije',
  `vat_rate` decimal(5, 2) NOT NULL COMMENT 'PDV stopa',
  `base_amount` decimal(15, 2) NOT NULL COMMENT 'Osnovica pre PDV-a',
  `vat_amount` decimal(15, 2) NOT NULL COMMENT 'Iznos PDV-a',
  `total_amount` decimal(15, 2) NOT NULL COMMENT 'Ukupan iznos sa PDV-om',
  `vat_type` enum('input','output') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Ulazni ili izlazni PDV',
  `tax_period` varchar(7) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Poreski period (GGGG-MM)',
  `is_submitted` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Da li je PDV prijavljen',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`vat_record_id`) USING BTREE,
  INDEX `idx_vat_company_id`(`company_id` ASC) USING BTREE,
  INDEX `idx_vat_invoice_id`(`invoice_id` ASC) USING BTREE,
  INDEX `idx_vat_tax_period`(`tax_period` ASC) USING BTREE,
  CONSTRAINT `vat_records_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`company_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'EN: Stores VAT transaction records | SR: ??uva PDV zapise' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of vat_records
-- ----------------------------

-- ----------------------------
-- View structure for v_ai_training_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_ai_training_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_ai_training_summary` AS select `ai_training_data`.`data_type` AS `data_type`,`ai_training_data`.`model_type` AS `model_type`,`ai_training_data`.`language` AS `language`,count(0) AS `record_count`,count(distinct `ai_training_data`.`company_id`) AS `companies_with_data`,count((case when (`ai_training_data`.`is_processed` = true) then 1 end)) AS `processed_records`,count((case when (`ai_training_data`.`is_processed` = false) then 1 end)) AS `unprocessed_records`,min(`ai_training_data`.`created_at`) AS `earliest_data`,max(`ai_training_data`.`created_at`) AS `latest_data`,count(distinct `ai_training_data`.`source_file`) AS `source_files` from `ai_training_data` group by `ai_training_data`.`data_type`,`ai_training_data`.`model_type`,`ai_training_data`.`language` order by `record_count` desc;

-- ----------------------------
-- View structure for v_anomaly_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_anomaly_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_anomaly_summary` AS select `c`.`company_id` AS `company_id`,`c`.`name` AS `company_name`,`c`.`industry` AS `industry`,`a`.`anomaly_type` AS `anomaly_type`,`a`.`severity` AS `severity`,count(`a`.`anomaly_id`) AS `anomaly_count`,count((case when (`a`.`status` = 'open') then 1 end)) AS `open_anomalies`,count((case when (`a`.`status` = 'investigating') then 1 end)) AS `investigating_anomalies`,count((case when (`a`.`status` = 'resolved') then 1 end)) AS `resolved_anomalies`,count((case when (`a`.`status` = 'false_positive') then 1 end)) AS `false_positives`,avg(`a`.`confidence_score`) AS `average_confidence`,min(`a`.`detected_at`) AS `first_anomaly_date`,max(`a`.`detected_at`) AS `latest_anomaly_date`,avg((to_days(coalesce(`a`.`resolved_at`,curdate())) - to_days(`a`.`detected_at`))) AS `average_resolution_days` from (`companies` `c` left join `anomalies` `a` on((`c`.`company_id` = `a`.`company_id`))) group by `c`.`company_id`,`c`.`name`,`c`.`industry`,`a`.`anomaly_type`,`a`.`severity` order by `c`.`company_id`,`a`.`severity` desc,`anomaly_count` desc;

-- ----------------------------
-- View structure for v_base_financial_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_base_financial_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_base_financial_summary` AS select `c`.`company_id` AS `company_id`,`c`.`name` AS `company_name`,date_format(`gl`.`transaction_date`,'%Y-%m') AS `period`,sum((case when (`coa`.`account_type` = 'revenue') then `gl`.`debit` else 0 end)) AS `total_income`,sum((case when (`coa`.`account_type` = 'expense') then `gl`.`credit` else 0 end)) AS `total_expense` from ((`companies` `c` left join `general_ledger` `gl` on((`c`.`company_id` = `gl`.`company_id`))) join `chart_of_accounts` `coa` on((`gl`.`account_id` = `coa`.`account_id`))) where (`c`.`is_active` = 1) group by `c`.`company_id`,`c`.`name`,date_format(`gl`.`transaction_date`,'%Y-%m');

-- ----------------------------
-- View structure for v_company_financial_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_company_financial_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_company_financial_summary` AS select `c`.`company_id` AS `company_id`,`c`.`name` AS `company_name`,`c`.`tax_id` AS `tax_id`,`c`.`city` AS `city`,`c`.`industry` AS `industry`,count(`fd`.`financial_data_id`) AS `total_transactions`,sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else 0 end)) AS `total_income`,sum((case when (`fd`.`transaction_type` = 'expense') then `fd`.`amount` else 0 end)) AS `total_expense`,sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else -(`fd`.`amount`) end)) AS `net_profit`,(case when (sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else 0 end)) > 0) then ((sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else -(`fd`.`amount`) end)) / sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else 0 end))) * 100) else 0 end) AS `profit_margin`,max(`fd`.`transaction_date`) AS `last_transaction_date` from (`companies` `c` left join `financial_data` `fd` on((`c`.`company_id` = `fd`.`company_id`))) where (`c`.`is_active` = true) group by `c`.`company_id`,`c`.`name`,`c`.`tax_id`,`c`.`city`,`c`.`industry`;

-- ----------------------------
-- View structure for v_company_operations_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_company_operations_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_company_operations_summary` AS select `c`.`company_id` AS `company_id`,`c`.`name` AS `company_name`,count(distinct `pm`.`manager_id`) AS `active_managers`,count(distinct `cp`.`project_id`) AS `active_projects`,sum((`i`.`quantity` * `i`.`unit_price`)) AS `inventory_value`,count(distinct `sc`.`contract_id`) AS `active_contracts`,count(distinct `et`.`training_id`) AS `training_completed` from (((((`companies` `c` left join `professional_managers` `pm` on(((`c`.`company_id` = `pm`.`company_id`) and (`pm`.`is_active` = 1)))) left join `construction_projects` `cp` on(((`c`.`company_id` = `cp`.`company_id`) and `cp`.`status_id` in (select `status_types`.`status_id` from `status_types` where (`status_types`.`status_name` in ('pending','active')))))) left join `inventory` `i` on((`c`.`company_id` = `i`.`company_id`))) left join `service_contracts` `sc` on(((`c`.`company_id` = `sc`.`company_id`) and `sc`.`status_id` in (select `status_types`.`status_id` from `status_types` where (`status_types`.`status_name` in ('pending','active')))))) left join `employee_training` `et` on((`c`.`company_id` = `et`.`company_id`))) where (`c`.`is_active` = 1) group by `c`.`company_id`,`c`.`name`;

-- ----------------------------
-- View structure for v_dashboard_metrics_summary
-- ----------------------------
DROP VIEW IF EXISTS `v_dashboard_metrics_summary`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_dashboard_metrics_summary` AS select `dashboard_metrics`.`metric_name` AS `metric_name`,`dashboard_metrics`.`metric_type` AS `metric_type`,count(0) AS `metric_count`,avg(`dashboard_metrics`.`metric_value`) AS `avg_value`,min(`dashboard_metrics`.`metric_value`) AS `min_value`,max(`dashboard_metrics`.`metric_value`) AS `max_value`,sum((case when (`dashboard_metrics`.`change_type` = 'increase') then 1 else 0 end)) AS `increasing_metrics`,sum((case when (`dashboard_metrics`.`change_type` = 'decrease') then 1 else 0 end)) AS `decreasing_metrics`,sum((case when (`dashboard_metrics`.`change_type` = 'no_change') then 1 else 0 end)) AS `stable_metrics`,count(distinct `dashboard_metrics`.`company_id`) AS `companies_with_metrics`,max(`dashboard_metrics`.`created_at`) AS `latest_metric_date` from `dashboard_metrics` group by `dashboard_metrics`.`metric_name`,`dashboard_metrics`.`metric_type` order by `metric_count` desc;

-- ----------------------------
-- View structure for v_employee_analytics
-- ----------------------------
DROP VIEW IF EXISTS `v_employee_analytics`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_employee_analytics` AS select `c`.`company_id` AS `company_id`,`c`.`name` AS `company_name`,`ed`.`department` AS `department`,count(`ed`.`employee_data_id`) AS `employee_count`,avg(`ed`.`salary`) AS `avg_salary`,min(`ed`.`salary`) AS `min_salary`,max(`ed`.`salary`) AS `max_salary`,sum(`ed`.`salary`) AS `total_salary_cost`,count((case when (`ed`.`is_active` = true) then 1 end)) AS `active_employees`,count((case when (`ed`.`is_active` = false) then 1 end)) AS `inactive_employees`,avg((to_days(curdate()) - to_days(`ed`.`hire_date`))) AS `avg_tenure_days`,min(`ed`.`hire_date`) AS `earliest_hire_date`,max(`ed`.`hire_date`) AS `latest_hire_date` from (`companies` `c` left join `employee_data` `ed` on((`c`.`company_id` = `ed`.`company_id`))) where (`c`.`is_active` = true) group by `c`.`company_id`,`c`.`name`,`ed`.`department` order by `c`.`company_id`,`ed`.`department`;

-- ----------------------------
-- View structure for v_location_financial_analysis
-- ----------------------------
DROP VIEW IF EXISTS `v_location_financial_analysis`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_location_financial_analysis` AS select `ld`.`city` AS `city`,`ld`.`region` AS `region`,`ld`.`country` AS `country`,count(distinct `fd`.`company_id`) AS `companies_in_location`,count(`fd`.`financial_data_id`) AS `total_transactions`,sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else 0 end)) AS `total_income`,sum((case when (`fd`.`transaction_type` = 'expense') then `fd`.`amount` else 0 end)) AS `total_expense`,sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else -(`fd`.`amount`) end)) AS `net_profit`,avg((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else NULL end)) AS `avg_income_per_transaction`,avg((case when (`fd`.`transaction_type` = 'expense') then `fd`.`amount` else NULL end)) AS `avg_expense_per_transaction`,count(distinct date_format(`fd`.`transaction_date`,'%Y-%m')) AS `active_months` from ((`location_data` `ld` join `companies` `c` on((`ld`.`city` = `c`.`city`))) join `financial_data` `fd` on((`c`.`company_id` = `fd`.`company_id`))) where ((`ld`.`is_active` = true) and (`c`.`is_active` = true)) group by `ld`.`city`,`ld`.`region`,`ld`.`country` order by `total_income` desc;

-- ----------------------------
-- View structure for v_monthly_financial_trends
-- ----------------------------
DROP VIEW IF EXISTS `v_monthly_financial_trends`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_monthly_financial_trends` AS select `c`.`company_id` AS `company_id`,`c`.`name` AS `company_name`,year(`fd`.`transaction_date`) AS `year`,month(`fd`.`transaction_date`) AS `month`,count(`fd`.`financial_data_id`) AS `transaction_count`,sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else 0 end)) AS `monthly_income`,sum((case when (`fd`.`transaction_type` = 'expense') then `fd`.`amount` else 0 end)) AS `monthly_expense`,sum((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else -(`fd`.`amount`) end)) AS `monthly_profit`,avg((case when (`fd`.`transaction_type` = 'income') then `fd`.`amount` else NULL end)) AS `avg_income_per_transaction`,avg((case when (`fd`.`transaction_type` = 'expense') then `fd`.`amount` else NULL end)) AS `avg_expense_per_transaction` from (`companies` `c` join `financial_data` `fd` on((`c`.`company_id` = `fd`.`company_id`))) where (`c`.`is_active` = true) group by `c`.`company_id`,`c`.`name`,year(`fd`.`transaction_date`),month(`fd`.`transaction_date`) order by `c`.`company_id`,`year`,`month`;

-- ----------------------------
-- Function structure for CalculateFinancialMetrics
-- ----------------------------
DROP FUNCTION IF EXISTS `CalculateFinancialMetrics`;
delimiter ;;
CREATE FUNCTION `CalculateFinancialMetrics`(company_id BIGINT, start_date DATE, end_date DATE)
 RETURNS json
  DETERMINISTIC
BEGIN
    RETURN JSON_OBJECT('net_profit', 0);
END
;;
delimiter ;

-- ----------------------------
-- Function structure for CalculateProjectBudgetStatus
-- ----------------------------
DROP FUNCTION IF EXISTS `CalculateProjectBudgetStatus`;
delimiter ;;
CREATE FUNCTION `CalculateProjectBudgetStatus`(project_id BIGINT)
 RETURNS json
  DETERMINISTIC
BEGIN
    RETURN JSON_OBJECT('budget', 0, 'spent', 0, 'remaining', 0);
END
;;
delimiter ;

-- ----------------------------
-- Function structure for CalculateProjectProfitability
-- ----------------------------
DROP FUNCTION IF EXISTS `CalculateProjectProfitability`;
delimiter ;;
CREATE FUNCTION `CalculateProjectProfitability`(project_id BIGINT)
 RETURNS json
  DETERMINISTIC
BEGIN
    RETURN JSON_OBJECT('profit', 0, 'profit_margin', 0);
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
